import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, Router } from '@angular/router';
import { CartService } from '../../core/services/cart.service';
import { Cart } from '../../core/models/cart.model';

@Component({
  selector: 'app-cart',
  standalone: true,
  imports: [CommonModule, RouterLink],
  template: `
    <div class="cart-page">
      <div class="container">
        <h1 class="page-title">Shopping Cart</h1>
        
        <!-- Loading State -->
        <div *ngIf="loading" class="loading-container">
          <div class="spinner"></div>
          <p>Loading your cart...</p>
        </div>

        <!-- Error State -->
        <div *ngIf="error" class="error-message">
          <p>{{ error }}</p>
          <button class="btn btn-primary" (click)="loadCart()">Try Again</button>
        </div>

        <!-- Empty Cart State -->
        <div *ngIf="!loading && !error && (!cart || cart.items.length === 0)" class="empty-cart">
          <div class="empty-cart-icon">
            <svg width="120" height="120" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
              <circle cx="9" cy="21" r="1"></circle>
              <circle cx="20" cy="21" r="1"></circle>
              <path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"></path>
            </svg>
          </div>
          <h2>Your cart is empty</h2>
          <p class="text-secondary">Looks like you haven't added any books yet.</p>
          <button class="btn btn-primary btn-lg" routerLink="/products">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
            <span>Total:</span>
            <span>₹{{ calculateTotal() }}</span>
          </div>
          <button class="checkout-btn" routerLink="/checkout">Proceed to Checkout</button>
        </div>
      </div>
      <div *ngIf="!cart || cart.items.length === 0" class="empty-cart">
        <p>Your cart is empty</p>
        <button routerLink="/products">Continue Shopping</button>
      </div>
    </div>
  `,
  styles: [`
    .cart-container {
      padding: 2rem;
      max-width: 1200px;
      margin: 0 auto;
    }
    .cart-content {
      display: grid;
      grid-template-columns: 2fr 1fr;
      gap: 2rem;
    }
    .cart-item {
      display: flex;
      gap: 1rem;
      padding: 1rem;
      background: var(--card-bg);
      border-radius: 8px;
      margin-bottom: 1rem;
    }
    .item-image {
      width: 100px;
      height: 150px;
      object-fit: cover;
      border-radius: 4px;
    }
    .cart-summary {
      background: var(--card-bg);
      padding: 1.5rem;
      border-radius: 8px;
      height: fit-content;
    }
    .checkout-btn {
      width: 100%;
      padding: 1rem;
      background: var(--accent-primary);
      color: white;
      border: none;
      border-radius: 8px;
      cursor: pointer;
      margin-top: 1rem;
    }
  `]
})
export class CartComponent implements OnInit {
  private cartService = inject(CartService);
  cart: Cart | null = null;

  ngOnInit() {
    this.loadCart();
  }

  loadCart() {
    this.cartService.getCart().subscribe(response => {
      this.cart = response.data;
    });
  }

  getProductImage(item: any): string {
    return item.product?.images?.[0]?.url || 'assets/placeholder.jpg';
  }

  getProductTitle(item: any): string {
    return item.product?.title || 'Product';
  }

  increaseQuantity(item: any) {
    const productId = typeof item.product === 'string' ? item.product : item.product._id;
    this.cartService.updateCartItem(productId, item.quantity + 1).subscribe(() => this.loadCart());
  }

  decreaseQuantity(item: any) {
    const productId = typeof item.product === 'string' ? item.product : item.product._id;
    if (item.quantity > 1) {
      this.cartService.updateCartItem(productId, item.quantity - 1).subscribe(() => this.loadCart());
    }
  }

  removeItem(item: any) {
    const productId = typeof item.product === 'string' ? item.product : item.product._id;
    this.cartService.removeFromCart(productId).subscribe(() => this.loadCart());
  }

  calculateTax(): number {
    return this.cart ? this.cart.totalPrice * 0.1 : 0;
  }

  calculateTotal(): number {
    return this.cart ? this.cart.totalPrice + this.calculateTax() : 0;
  }
}

